module top_module(
  input CLK,
  input EN,
  input TE,
  output ENCLK
);reg clk_gating_output;

  always @(*) begin
    if (EN) begin
      clk_gating_output <= CLK;
    end else if (TE) begin
      clk_gating_output <= TE;
    end else begin
      clk_gating_output <= 1'b0;
    end
  end

  assign ENCLK = clk_gating_output;

endmodule
